-- Заполнение полных описаний достопримечательностей для маршрутов 5-8
-- Источник текста: PDF "Yuzhnye_i_zapadnye_marshruty (2).pdf" (раздел "Северные и восточные маршруты")
-- Обновляем [достопримечательность].[описание] по связке (id_маршрута + порядок_следования),
-- чтобы не зависеть от точного совпадения названий.

SET NOCOUNT ON;

DECLARE @routeId INT;
DECLARE @ord INT;

--------------------------------------------------------------------------------
-- Route 5: Променад по линиям Васильевского острова (Северное)
--------------------------------------------------------------------------------
SELECT @routeId = [id_маршрута] FROM [маршрут] WHERE [название] = N'Променад по линиям Васильевского острова';
IF @routeId IS NULL
BEGIN
  RAISERROR(N'Маршрут 5 не найден в таблице [маршрут].', 16, 1);
  RETURN;
END

-- 5.1 Военно-морской музей
SET @ord = 1;
UPDATE a
SET a.[описание] = N'От здания университета сверните на улицу Труда и следуйте до пересечения с Крюковым каналом. Здесь, в историческом комплексе Крюковских (Морских) казарм, расположен Центральный военно-морской музей имени императора Петра Великого.

Это один из старейших и крупнейших морских музеев мира, чья история началась в 1709 году с указа Петра I о создании Модель-камеры для хранения корабельных чертежей и моделей. Более двух веков, с 1941 по 2013 год, его коллекция размещалась в величественном здании Биржи на Стрелке Васильевского острова, а затем переехала в просторные залы казарм, что позволило показать публике гораздо больше уникальных экспонатов.

Основу собрания, которое насчитывает свыше 700 000 предметов, заложил сам Пётр. Главной реликвией и символом музея по праву считается Ботик Петра I, тот самый, который царь называл «дедушкой русского флота». Помимо него, здесь хранятся подлинные исторические суда, такие как старейшая сохранившаяся русская подводная лодка, великолепная коллекция корабельных флагов, включая флаги корабля «Ингерманланд» 1715 года, а также работы знаменитых маринистов – Айвазовского, Боголюбова.

Сегодня музей — это целый флотский мир под одной крышей. Вы сможете проследить, как от петровской модели галеры российский флот вырос в могучую эскадру парусных гигантов, а затем в атомный океанский ракетоносец. Отдельные залы посвящены кругосветным плаваниям русских моряков, легендарным морским сражениям и истории военно-морского образования.

Важно отметить, что филиалами музея являются крейсер «Аврора», подводная лодка «Народоволец» и мемориальный комплекс «Дорога жизни» в Кронштадте. Посещение этого музея — это погружение в эпическую историю страны, которая навсегда связала свою судьбу с морскими просторами, и знакомство с подвигами, технологиями и судьбами тех, кто эту историю создавал.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.2 Особняк Румянцева
SET @ord = 2;
UPDATE a
SET a.[описание] = N'Гуляя вдоль Английской набережной перед вами предстанет величественный Особняк Румянцева. Этот дом — настоящая находка для ценителя петербургской истории. Он уникален тем, что это единственный сохранившийся на Английской набережной особняк в стиле классицизма, дошедший до нас практически без изменений с первой половины XIX века. Сейчас здесь располагается филиал Государственного музея истории Санкт-Петербурга.

Облик, который мы видим сегодня, особняк приобрёл при графе Николае Петровиче Румянцеве — выдающемся государственном деятеле, канцлере и знаменитом меценате. Он купил это здание в 1802 году. Граф был страстным коллекционером и покровителем наук. Его библиотека, коллекции монет, рукописей и этнографических редкостей легли в основу Румянцевского музея, который позже переехал в Москву и стал частью знаменитой Ленинской библиотеки.

После его смерти в 1826 году брат, Сергей Петрович Румянцев, решил увековечить память о нём. Он заказал знаменитому архитектору Василию Глинке масштабную перестройку. В 1827 году фасад украсил грандиозный портик с двенадцатью колоннами и аллегорической скульптурной композицией.

Войдя внутрь, вы попадёте в роскошные парадные интерьеры эпохи русского ампира. Центром притяжения является знаменитая Белоколонная гостиная — бальный зал с двумя рядами белоснежных коринфских колонн. Это один из самых грандиозных и красивых залов Петербурга первой половины XIX века, где при свете хрустальных люстр проходили великосветские приёмы и балы. Сохранились и другие помещения: Голубая и Зелёная гостиные, Кабинет графа, воссозданные по архивным документам.

Судьба особняка отразила судьбу города. После Румянцевых им владели богатейшие купцы и промышленники, а в 1916 году его последняя хозяйка продала здание городу. После революции здесь размещались коммунальные квартиры, что чудом не погубило интерьеры. С 1938 года в особняке открылась постоянная выставка «История Петербурга-Петрограда. 1703-1918», которая работает и сегодня.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.3 Музей-квартира И.П. Павлова
SET @ord = 3;
UPDATE a
SET a.[описание] = N'Перейдите Неву по Благовещенскому мосту и на Васильевском острове сверните на 7-ю линию. На углу, в доме №2, вы увидите пятиэтажное здание в стиле модерн. Это и есть место, где более трех десятилетий жил и работал первый русский нобелевский лауреат — Иван Петрович Павлов.

Мемориальный музей-квартира И.П. Павлова расположена на 2-м этаже, в квартире №11. Ученый вселился сюда в 1918 году по ходатайству Академии наук и прожил здесь до своей смерти в 1936 году. Это не просто квартира, а настоящая «рабочая крепость» гения, где сочетались семейный быт и научный поиск мирового уровня. Его кабинет и рабочий стол, которые вы увидите, стали центром, откуда шло руководство Институтом физиологии АН СССР. Именно здесь он готовил свои знаменитые «Павловские среды» — научные семинары, на которые съезжались физиологи со всей страны.

Обстановка квартиры простая, даже аскетичная. Но каждая деталь здесь подлинная и дышит историей. В прихожей висит его неизменное пальто и шляпа. В кабинете — массивный письменный стол, за которым был написан не один научный труд, и библиотека с книгами на разных языках. Отдельная комната — «мышиная» — была отдана под содержание лабораторных животных, что для того времени было уникальным явлением для жилого дома.

Особая атмосфера царит в столовой. Здесь за большим столом собиралась не только семья, но и гости — коллеги, ученики, зарубежные ученые. Именно в этой квартире в 1935 году Павлова посетил знаменитый английский писатель-фантаст Герберт Уэллс, оставивший яркие воспоминания о встрече.

Но главное, что передает этот музей, — невероятную силу духа и преданность науке. Его квартира была островком независимой мысли. Пройдя по этим комнатам, вы почувствуете, как в простой петербургской квартире рождались идеи, изменившие мировую науку о мозге и поведении. Это скромный, но очень мощный памятник несгибаемому интеллекту и гражданскому мужеству.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.4 Аптека доктора Пеля и Ф.К. Феррейна
SET @ord = 4;
UPDATE a
SET a.[описание] = N'Пройдя на 6-ю линию Васильевского острова, поверните налево, и перед вами откроется вид на уникальное здание, прозванное в народе «Башня грифонов». Это и есть историческая аптека доктора Пеля, а позже — товарищества «Феррейн».

Это не просто аптека, а целый аптекарский миф Петербурга, место, где наука сплелась с городскими легендами. История этого углового здания началась в 1760 году, но настоящую славу ему принес Вильгельм Христофорович Пель, провизор и ученый, открывший здесь в 1850-х годах «Аптеку доктора Пеля и сыновей». При нем это место стало центром не только торговли, но и серьёзных научных исследований. В лабораториях аптеки изготавливали редкие и сложные лекарства, а сам доктор Пель читал лекции по фармацевтической химии в университете.

Но главная легенда связана с его сыном, Александром Вильгельмовичем Пелем. Он увлекался алхимией и астрономией. По преданию, именно он построил во дворе аптеки ту самую кирпичную трубу-обсерваторию, которую мы называем «Башней грифонов». На её стене до сих пор видны загадочные цифры. Говорят, это некий магический шифр или нумерологический код. А грифоны, мифические стражи сокровищ, по легенде, охраняли алхимические секреты доктора. Считается, что если загадать желание, обойти башню и сосчитать всех грифонов, то желание сбудется. Сколько их на самом деле — вот загадка для каждого гостя.

В 1871 году аптеку приобрел Владимир Карлович Феррейн, основатель крупнейшей в России аптечной сети «Товарищество В.К. Феррейна». При нем производство расширилось до промышленных масштабов. В комплекс вошли химико-фармацевтическая фабрика, оранжереи лекарственных растений на Мичуринской улице и даже собственная пасека. Аптека на 6-й линии стала флагманской, в её исторических интерьерах сохранились роскошные деревянные шкафы, витрины и массивная конторка. Вы можете зайти внутрь и ощутить атмосферу старинной, но действующей аптеки, где до сих пор готовят лекарства по индивидуальным рецептам.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.5 Андреевский собор
SET @ord = 5;
UPDATE a
SET a.[описание] = N'Если идти по 6-й линии Васильевского острова в сторону Большого проспекта вы упретесь в живописный сквер, и перед вами откроется величественный вид на Андреевский собор с его высокой колокольней.

Этот собор — сердце Васильевского острова и один из старейших храмов города. Его история началась еще при Петре I, в 1728 году, с небольшой деревянной церкви, освященной в честь апостола Андрея Первозванного — небесного покровителя Российского флота и самого императора. Каменный собор, который мы видим сегодня, был заложен в 1764 году по проекту знаменитого архитектора Александра Виста, а достраивался уже после его смерти. Освятили его только в 1780 году, и с тех пор его строгий, величественный облик в стиле раннего классицизма почти не менялся.

Главная святыня собора, вокруг которой строилась его жизнь, — это старинный образ святого апостола Андрея Первозванного. Эту икону подарил собору еще его основатель, князь Александр Меншиков. Собор был главным орденским храмом ордена Святого Андрея Первозванного — высшей награды Российской империи. Здесь проходили торжественные службы в дни орденских праздников.

Внутри храм поражает своим простором и светом. Он имеет форму равноконечного креста и вмещает до пяти тысяч человек. Особого внимания заслуживает великолепный пятиярусный резной иконостас с позолотой, созданный в конце XVIII века. Он является настоящим произведением искусства. А с трехъярусной колокольни, которая служит главным архитектурным акцентом площади, открывается прекрасный вид на историческую часть острова.

Но известность собора связана не только с его статусом. В 19 веке он стал настоящим духовным центром для ученых и студентов соседнего университета. А в советское время его постигла тяжелая судьба: в 1938 году храм был закрыт, а его здание передали под нужды Ленгоргеологии. Уникальные интерьеры чудом не были уничтожены, но потребовалась масштабная реставрация, которая началась в 1990-х годах. Богослужения возобновились в 1992 году, и с тех пор собор снова стал действующим.

Сегодня, стоя на этой площади, вы чувствуете связь эпох. Вы видите храм, который пережил и имперский расцвет, и годы запустения, и возрождение. Это не просто архитектурный памятник, а живое свидетельство истории.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.6 Музей повседневной культуры Ленинграда 1945-1965 гг.
SET @ord = 6;
UPDATE a
SET a.[описание] = N'Проходя по 6-й линии пройдите вперед до дома №19. Здесь, в парадной обычного петербургского дома, на третьем этаже находится уникальное место — Музей повседневной культуры Ленинграда 1945-1965 годов. Это негосударственный музей, созданный силами энтузиастов, и его часто называют «музеем коммунального быта».

Попасть сюда — значит совершить путешествие в недавнее, но уже ушедшее прошлое наших родителей и бабушек. Музей занимает комнаты бывшей коммунальной квартиры, и это его главная особенность. Вы не просто увидите вещи послевоенной эпохи, а окажетесь в реальном пространстве, где они когда-то использовались. Период, который охватывает экспозиция, — это время от Победы до начала эпохи «застоя», время надежд, тяжелого восстановления и скромного быта.

Переступив порог, вы попадете в типичную коммуналку с длинным коридором, от которого отходят комнаты. Каждая из них воссоздает определенный уголок жизни ленинградцев. Вот кухня с примусом, жестяными противнями и характерной красно-белой занавеской на окне. Вот детский уголок с деревянными игрушками, школьной формой и портретом Юрия Гагарина на стене. Особое впечатление производит комната «девушки-современницы» с узкой железной кроватью, этажеркой для книг, патефоном и платьем, готовым для похода на танцы.

Но этот музей — не только о вещах. Он о людях и их стратегиях выживания и радости. Вы узнаете, как в условиях дефицита и тесноты создавался уют, как мастерили абажуры из ничего, и как ценили каждую редкую вещь — будь то хрустальная вазочка или импортные духи «Красная Москва».

Одна из самых сильных сторон музея — его подлинность. Практически все экспонаты подарены самими жителями города. Это не бутафория, а настоящие предметы, хранящие память и энергию своего времени. Основатели музея, историк Лев Лурье и коллекционер Олег Николаев, создали его именно как памятник обычному человеку, чья частная жизнь долгое время оставалась «за кадром» большой истории.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.7 Лютеранский Михайловский собор
SET @ord = 7;
UPDATE a
SET a.[описание] = N'Лютеранский Михайловский собор - не только один из красивейших лютеранских храмов России, но и важнейший памятник истории и архитектуры Санкт-Петербурга. Он был построен в 1874-1876 годах для нужд быстро растущей немецкой лютеранской общины Васильевского острова, которая к тому времени уже насчитывала более 6 тысяч человек. Средства на строительство собирали всем миром, значительную часть пожертвовали купцы-немцы. Архитектор Карл Карлович Бульмеринг создал проект в неоготическом стиле, который был популярен для протестантских храмов Европы. Вы сразу обратите внимание на остроконечные шпили, стрельчатые окна и контрфорсы — все эти элементы характерны для готики.

Храм освятили в честь Архангела Михаила, покровителя воинов, но в городе его чаще называли и называют просто «немецкой церковью». Внутри он впечатляет своим пространством и светом. Центральный зал вмещал до 1200 молящихся. Интерьер был строгим, как и полагается лютеранской кирхе, но очень изящным. Гордостью собора был большой орган фирмы «Э.Ф. Валькер» и изящная деревянная кафедра для проповедей.

Судьба собора в XX веке была драматичной. После революции, в 1935 году, его закрыли, а здание передали под склад и различные учреждения. Во время войны в него попал снаряд, серьезно повредивший алтарную часть. Долгие десятилетия собор стоял в запустении, постепенно разрушаясь. Возрождение началось только в 1992 году, когда здание было возвращено возрожденной лютеранской общине. Реставрация заняла почти 20 лет и стала примером научного подхода: специалисты бережно воссоздали и фасады, и интерьеры, включая витражи и шпили.

Сегодня собор снова действует. В нем проходят не только богослужения, но и концерты органной и классической музыки — акустика здесь превосходная. Подойдя ближе, вы оцените тонкую кирпичную кладку и ощутите дух той самой «немецкой» части Петербурга, которая всегда была неотъемлемой частью его идентичности. Это место — символ утрат и возвращения, рассказ о том, как город медленно, но верно исцеляет свои исторические раны.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.8 Музей-квартира семьи Бенуа
SET @ord = 8;
UPDATE a
SET a.[описание] = N'Прогуливаясь по 3-ей линии Васильевского острова, вы увидите скромный, но изящный трехэтажный особняк в стиле классицизма. Это музей-квартира семьи Бенуа — уникальное место, где история одного рода стала историей русской культуры.

Этот дом — не просто музей, а настоящий родовое гнездо, в котором жили представители знаменитой династии Бенуа на протяжении почти столетия, с 1890-х по 1970-е годы. Семья Бенуа — это целая вселенная в русском искусстве: архитекторы, художники, скульпторы, искусствоведы, композиторы. Альберт Николаевич Бенуа, акварелист и профессор Академии художеств, поселился здесь с семьей, и квартира стала творческим эпицентром.

Главная ценность этого места в его подлинности. Это не реконструкция, а сохраненная в почти нетронутом виде жилая среда. Вы попадаете в мир, который не менялся десятилетиями. Войдя, вы оказываетесь в прихожей, где на вешалке до сих пор висит пальто хозяина, а на стене — старые фотографии. Затем — уютная гостиная, где стоит рояль фирмы «Беккер», за которым музицировали. За ним — кабинет Альберта Николаевича, хранящий атмосферу рабочего процесса: мольберт, этюды, кисти, книги.

Но, пожалуй, самое сильное впечатление производит столовая. Здесь все осталось так, как будто хозяева только что вышли. На столе — сервиз, на буфете — фарфор, на стенах — семейные портреты и работы самих Бенуа. Кажется, вот-вот раздадутся голоса, смех, начнется оживленная беседа об искусстве. В этой квартире бывали Репин, Бакст, Сомов, Стравинский. Здесь рождались идеи, обсуждались проекты, звучала музыка.

Музей был создан в 1988 году благодаря усилиям внучки Альберта Бенуа — Ирины Николаевны Бенуа, которая и передала семейное наследие городу. Она сохранила не только вещи, но и дух дома. Экспозиция рассказывает не только о самом Альберте Николаевиче, но и о других ярких представителях династии.

Посещение этой квартиры — это редкая возможность прикоснуться к подлинной, непарадной жизни творческой интеллигенции Серебряного века и советского времени. Вы не увидите здесь пышных интерьеров, зато почувствуете тепло семейного очага, который согревал и вдохновлял несколько поколений одной из самых талантливых семей России.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.9 Дом купца Бекаля
SET @ord = 9;
UPDATE a
SET a.[описание] = N'Прогуливаясь по 2-й линии Васильевского острова, вы увидите нарядный, доходный дом купца Петра Яковлевича Бекеля — образец престижной деловой архитектуры Петербурга конца XIX века, чья история стала историей технического прогресса и научной мысли.

Этот дом — не просто жилое здание, а настоящий деловой центр своего времени, построенный в 1881–1883 годах по проекту архитектора Фёдора Ивановича Пуншеля. Здесь, в стенах собственного особняка, купец первой гильдии Пётр Бекель разместил правление своего «Углепромышленного и торгового общества “Павел Бекель”». Квартиры сдавались внаём, а офисы арендовали крупные компании. Это было место, где кипели коммерческие дела и принимались важные финансовые решения.

Войдя, вы бы оказались в пространстве, где уже было проведено электричество, телефон, паровое отопление и даже работал лифт. Парадные интерьеры поражали воображение: мраморная лестница, витражи, лепнина и собственный зимний сад. Фасад, отделанный гранитом, цветным кирпичом и майоликой, с коваными элементами, демонстрировал эклектичную моду и финансовый успех хозяина.

Но, пожалуй, самое сильное впечатление производит судьба здания после 1917 года. Оно не было разорено, а получило новую, научную жизнь. В 1920-х годах сюда вселился Государственный гидрологический институт, который находится здесь и сегодня. Научное учреждение, в отличие от коммунальных квартир, позволило частично сохранить исторические интерьеры. Правда, в 1932 году здание надстроили двумя этажами, что изменило его первоначальный, более гармоничный облик.

История дома отразила путь города: от частного капитала и технической роскоши к общественной науке. Посещение этого здания — это редкая возможность увидеть, как купеческая предприимчивость, воплощённая в камне и стали, плавно перетекла в служение точному знанию. Вы не найдёте здесь семейных реликвий, зато почувствуете дух делового Петербурга, который и сегодня продолжает свою работу в тишине научных кабинетов.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

-- 5.10 Екатерининская лютеранская церковь (Кирха Св. Екатерины)
SET @ord = 10;
UPDATE a
SET a.[описание] = N'Прогуливаясь по Большому проспекту Васильевского острова ваш взгляд непременно остановится на величественном здании кирпича со строгой башней и шпилем. Это Екатерининская лютеранская церковь, или Кирха Святой Екатерины, — духовное сердце и архитектурная доминанта немецкой общины Васильевского острова.

Этот храм — не просто памятник архитектуры, а живое свидетельство почти трёхвековой истории. Его история началась в 1728 году с основания лютеранской общины, объединившей немецких мастеровых, учёных и купцов, приглашённых Петром I строить новую столицу. Каменный храм, который мы видим сегодня, был возведён позже и освящён в 1771 году. Средства на его строительство собирала вся община, а значительную помощь оказала сама императрица Екатерина II, в честь которой церковь и получила своё имя.

Главная ценность этого места — в его удивительной судьбе, в которой переплелись вера, культура и воля к сохранению. Архитектор Юрий Фельтен создал здание в духе строгого классицизма. Гордостью кирхи всегда был её орган. Если в XIX веке здесь звучал инструмент мастера Метцеля, то сегодня в зале установлен один из лучших в Петербурге механических органов современной работы, наследующий эту музыкальную традицию.

Но, пожалуй, самое сильное впечатление производит осознание того, как здание пережило XX век. В 1935 году церковь была закрыта, а её пасторы — репрессированы. Казалось, история немецкого прихода навсегда прервалась. Однако уникальная акустика зала спасла его от разрушения: здесь разместилась студия грамзаписи «Мелодия». Именно в этих стенах записывали свои произведения Шостакович и Свиридов, а стены, помнившие лютеранские хоралы, стали хранителями советской музыкальной классики.

Возрождение началось в 1989 году, когда в здании вновь провели рождественскую службу, а в 1996 году кирха была официально возвращена церкви. Сегодня это вновь действующий храм, но его двери открыты для всех. Здесь проходят не только богослужения, но и концерты органной музыки, лекции и выставки. Посещение этого места — это возможность прикоснуться к подлинному культурному слою Петербурга, где немецкая педантичность, русская духовность и всеобщая любовь к музыке создали уникальное пространство. Вы почувствуете не холод музея, а тепло живого дома, который, несмотря на все исторические бури, сумел сохранить своё высокое предназначение.'
FROM [достопримечательность] a
JOIN [точка_маршрута] p ON p.[id_достопримечательности] = a.[id_достопримечательности]
WHERE p.[id_маршрута] = @routeId AND p.[порядок_следования] = @ord;

--------------------------------------------------------------------------------
-- Route 6: Прогулка до стрелки Васильевского острова (Северное)
--------------------------------------------------------------------------------
SELECT @routeId = [id_маршрута] FROM [маршрут] WHERE [название] IN (
  N'Прогулка до стрелки Васильевского острова',
  N'По следам императоров и академиков: путь к стрелке Васильевского острова'
);
IF @routeId IS NULL
BEGIN
  RAISERROR(N'Маршрут 6 не найден в таблице [маршрут].', 16, 1);
  RETURN;
END

-- 6.1 Николаевский дворец
SET @ord = 1;
UPDATE a SET a.[описание] = N'Если от здания ГУАП пройти до площади Труда, перед вами откроется величественное здание из серо-жёлтого песчаника. Это Николаевский дворец, который петербуржцы долгое время знали как Дворец Труда.

Этот дворец стал подарком императора Николая I своему третьему сыну, великому князю Николаю Николаевичу, к его совершеннолетию. Строили его с 1853 по 1861 год, архитектор выбрал для фасада стиль итальянского Ренессанса, но наполнил здание самыми передовыми для своего времени технологиями. Представьте, в 1860-х годах здесь уже были проведены водопровод, канализация, паровое отопление, телеграф и даже гидравлический лифт. Дворец был не просто красивым, он был умным.

Но за величественным фасадом и техническими чудесами скрывается особая, почти личная история. Великий князь Николай Николаевич совершив паломничество в Иерусалим, был так потрясён посещением Гроба Господня, что велел устроить точную его копию в подвале домовой церкви дворца, освящённой в честь иконы «Всех скорбящих Радость». Эта уникальная пещерная церковь, скрытая от посторонних глаз, стала духовным сердцем его дома.

После смерти князя дворец не опустел. В 1895 году сюда переехал Ксениинский институт — одно из лучших в России женских учебных заведений для благородных девиц. А с приходом советской власти здание получило новое имя — Дворец Труда — и новую судьбу. С 1918 года здесь разместились профсоюзы. В блокадные годы в этих стенах работал главный военный госпиталь города, а на крыше дежурили наблюдатели ПВО. Совсем недавно, в 2025 году, у дворца началась очередная глава: он был передан Санкт-Петербургской государственной консерватории. Так что, возможно, вскоре его залы вновь наполнятся музыкой.

Пройдя внутрь, вы попадёте в вестибюль с мощными гранитными колоннами и тут же оцените грандиозную парадную лестницу, ведущую наверх. Она выводит в анфиладу роскошных залов. Особенно впечатляют двусветные Танцевальный и Банкетный залы высотой 17 метров. Их убранство, лепнина, свет — всё говорит о былом величии и светской жизни, кипевшей здесь при княжеском дворе. В некоторых помещениях сохранились экспозиции Музея истории профсоюзного движения, рассказывающие уже о другой, советской эпохе жизни этого здания.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 6.2 Научно-исследовательский музей при Российской академии художеств
SET @ord = 2;
UPDATE a SET a.[описание] = N'Прогуливаясь по Университетской набережной Васильевского острова, обратите внимание на величественное здание с куполом— это знаменитая Императорская Академия художеств. За его строгим классическим фасадом, спроектированным архитекторами Александром Кокориновым и Жан-Батистом Валлен-Деламотом, скрывается настоящая сокровищница — Научно-исследовательский музей Российской академии художеств.

Зайдя внутрь, вы попадёте не просто в музей, а в сердце русской художественной школы. Именно здесь, в этих стенах, начиная с 1758 года, учились и создавали свои первые шедевры поколения великих русских художников. А собрание музея изначально формировалось не для праздного любования, а как уникальное учебное пособие для студентов. Это был первый в России художественный музей, открытый для публики всех сословий.

Основа коллекции была заложена одним из основателей Академии, графом Иваном Ивановичем Шуваловым, который передал в дар своё личное собрание западноевропейской живописи, включавшее работы Рембрандта. Вслед за ним императрица Екатерина II преподнесла в дар произведения известного художника Антона Менгса. Но настоящим прорывом стал 1862 год, когда граф Николай Александрович Кушелев-Безбородко завещал Академии свою блестящую коллекцию из почти пятисот картин и скульптур европейских мастеров, включая работы Питера Брейгеля Старшего и Питера Пауля Рубенса. Согласно воле графа, это собрание должно было стать публичной галереей.

В XX веке музей пережил сложные времена: значительная часть его коллекции, включая полотна Карла Брюллова, была передана в Эрмитаж и Русский музей. Но в 1933 году музей возродили, и сегодня он с гордостью носит своё современное научное название.

Обязательно загляните в парадные залы главного корпуса. Их росписи — тоже часть учебного процесса. В XIX веке лучшие выпускники-пенсионеры отправлялись в Италию, и их «заданием» было создавать копии фресок Рафаэля в Ватикане или картин Тициана. Эти великолепные копии, привезённые обратно в Академию, украсили её стены и служили эталоном для следующих поколений студентов.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 6.3 Румянцевский сад
SET @ord = 3;
UPDATE a SET a.[описание] = N'Прямо за Академией художеств, между её главным корпусом и 2-й линией Васильевского острова, находится небольшой, но очень исторический Румянцевский сад.

Этот сад — отличный пример того, как в Петербурге переплетаются разные эпохи. Сама земля здесь имеет давнюю историю: в XVIII веке на этом месте стоял дом первого градоначальника города, Александра Даниловича Меншикова. Позже участок перешёл к князьям Голицыным. Но своим появлением и названием сад обязан не им.

В 1818 году на соседней Васильевской площади (сейчас она называется площадью Шевченко) был установлен обелиск «Румянцева победам». Этот памятник, созданный архитектором Винченцо Бренной ещё в 1799 году, первоначально стоял на Марсовом поле в честь побед выдающегося русского полководца екатерининской эпохи — графа Петра Александровича Румянцева-Задунайского. Когда памятник перенесли на Васильевский остров, окружающую территорию решено было благоустроить. Так в 1866-1867 годах и появился Румянцевский сад, разбитый по проекту садового мастера И.П. Визе.

Но главное украшение сада появилось позже. В 1870-х годах здесь были установлены два изящных фонтана, которые придают месту особенное очарование. Это не новые сооружения: фонтаны были перенесены сюда с Пулковского шоссе, где они прежде украшали гранитную набережную Невы у Адмиралтейства. К сожалению, их автор неизвестен, но их классические формы отлично вписались в атмосферу сада.

После революции 1917 года обелиск «Румянцева победам» демонтировали, а сад переименовали в сад имени Вильгельма Пегельмана. Историческое название — Румянцевский сад — было возвращено только в 2001 году. Обелиск же на площадь так и не вернули; сегодня на его месте стоит памятник Тарасу Шевченко. А сам обелиск почти сто лет скромно стоит во дворе Академии художеств, недалеко от того места, где он когда-то возвышался.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 6.4 Дворец Меншикова
SET @ord = 4;
UPDATE a SET a.[описание] = N'Дворец Александра Даниловича Меншикова на Университетской набережной - это не просто дворец, а первое каменное жилое здание Санкт-Петербурга, заложенное в 1710 году.

Давайте представим эту набережную в те времена. Вместо гранита — деревянные настилы, вместо величественных фасадов — пустынный болотистый берег. И на этом берегу светлейший князь Меншиков, ближайший друг и сподвижник Петра Великого, решает выстроить себе резиденцию, которая должна была затмить всё вокруг. Архитекторы Джованни Мария Фонтана и Готфрид Иоганн Шедель возвели не просто дом, а символ новой эпохи в стиле петровского барокко. Говорят, что роскошь интерьеров даже превосходила убранство скромных покоев самого царя. Стены были выкрашены не в привычный жёлтый, а в насыщенный тёмно-серый, «асфальтовый» цвет, который оттеняли белоснежные наличники и позолоченные детали. Это был смелый контрастный образ молодой столицы.

Этот дворец сразу стал настоящим центром политической и светской жизни. Пётр I проводил здесь дипломатические приёмы, шумные ассамблеи и даже дал резиденции почётное название — «Посольский дом». Именно в этих стенах пировали по случаю побед в Северной войне, именно здесь решались важнейшие государственные дела. Дворец видел и взлёт, и стремительное падение своего хозяина. После смерти Петра I и воцарения Екатерины I Меншиков достиг вершины власти, фактически став правителем России. Но уже в 1727 году, при юном Петре II, он впал в немилость, был арестован, лишён всего состояния и сослан в Берёзов, где и закончил свои дни. Его великолепный дворец был конфискован в казну.

На этом его жизнь не закончилась. Более чем на 250 лет здание перешло к Первому кадетскому корпусу — привилегированному военному училищу. Для нужд учебного заведения дворец перестроили: исчезли мансардная крыша, многие скульптуры, а интерьеры были приспособлены под классы и казармы. Казалось, память о Меншикове навсегда стёрта. Но в середине XX века началась грандиозная работа реставраторов. По крупицам, по старинным документам и открытиям под поздними слоями штукатурки, они стали возвращать дому его первоначальный облик. И в 1981 году дворец возродился уже как филиал Государственного Эрмитажа.

Сегодня вы сможете пройти по анфиладам парадных залов, где под высокими потолками сохранилась лепнина, а стены некоторых комнат, например, «Орехового» кабинета, облицованы дубовыми панелями с тончайшей резьбой. Особое очарование — комнаты, отделанные голландскими изразцами с синими рисунками, которые так любил Пётр. Вы увидите подлинные предметы быта, мебель, портреты самого Меншикова и его современников из богатейшей коллекции Эрмитажа.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 6.5 Дворец Петра II
SET @ord = 5;
UPDATE a SET a.[описание] = N'Прогуливаясь по Университетской набережной Васильевского острова, прямо напротив Кунсткамеры, вы можете заметить скромное двухэтажное здание жёлтого цвета. Перед вами — Дворец Петра II, одна из самых недооценённых и грустных построек Петербурга.

Этот дворец — настоящий ребёнок своей бурной эпохи, а точнее, политической интриги. Его начали спешно возводить в 1727 году по указу всесильного Александра Даниловича Меншикова, светлейшего князя и ближайшего сподвижника Петра Великого. На тот момент Меншиков достиг пика своего могущества: после смерти Екатерины I он был фактическим правителем России при малолетнем императоре Петре II Алексеевиче, который приходился ему зятем. Чтобы окончательно привязать юного монарха к себе и к новой столице, а не к старой Москве, Меншиков задумал грандиозный проект. Он решил построить для Петра II отдельную резиденцию прямо напротив здания Двенадцати коллегий — центра власти империи, связав её крытой галереей со своим собственным дворцом.

Строительство поручили архитектору Доменико Трезини, первому зодчему Петербурга. План был масштабным: помимо самого дворца, планировались сад, фонтан и гавань для яхт императора. Однако судьба распорядилась иначе. Летом 1727 года Меншиков впал в немилость, был арестован и сослан. Вместе с ним рухнули и все его планы.

Юный Пётр II, освободившись от опеки, не пожелал оставаться в ненавистном ему Петербурге и в начале 1728 года навсегда уехал в Москву, где вскоре и скончался от оспы. Дворец, предназначенный для императора, так и не принял своего хозяина. Он стал символом несбывшихся амбиций и мимолётности власти.

Дальнейшая судьба здания — череда переделок и утрат. Позднее его передали Первому кадетскому корпусу. Для нужд учебного заведения дворец многократно перестраивали: разобрали высокую крышу и фронтоны, заложили некоторые окна, изменили планировку. От первоначального великолепия Трезини практически ничего не осталось снаружи. Более того, его даже перестали узнавать. Долгое время здание считалось просто одним из корпусов Кадетского корпуса, и только тщательные историко-архитектурные исследования в XX веке позволили установить его подлинную, императорскую «биографию».

Сегодня в этом здании находится один из факультетов Санкт-Петербургского государственного университета. Пройдя внутрь, вы вряд ли увидите парадные залы — скорее, современные аудитории и коридоры. Однако это не просто дворец-призрак. Это немой свидетель того, как история может свернуть с намеченного пути, оставив после себя лишь тихое, неприметное здание, хранящее память о грандиозной интриге, которая так и не сбылась.'
