-- Route 7: Парадный Петербург: по набережной к Эрмитажу (Восточное)
--------------------------------------------------------------------------------
SELECT @routeId = [id_маршрута] FROM [маршрут] WHERE [название] = N'Парадный Петербург: по набережной к Эрмитажу';
IF @routeId IS NULL
BEGIN
  RAISERROR(N'Маршрут 7 не найден в таблице [маршрут].', 16, 1);
  RETURN;
END

-- 7.1 Конногвардейский бульвар и манеж
SET @ord = 1;
UPDATE a SET a.[описание] = N'Маршрут начинается от Конногвардейского бульвара — одного из старейших бульваров города, протянувшегося от Сенатской и Исаакиевской площадей до площади Труда. История этого места уходит в начало 18 века, когда здесь протекал Адмиралтейский канал, прорытый для доставки леса от Новой Голландии к верфи. На его берегах располагались Канатный и Прядильный дворы, где изготавливали и хранили корабельные снасти. В 1844–1845 годах канал заключили в трубу, и по проекту архитектора Николая Ефимовича Ефимова разбили бульвар.

В начале бульвара, со стороны Сенатской площади, ваше внимание привлекут две величественные гранитные колонны, увенчанные бронзовыми фигурами крылатых Побед. Это подарок прусского короля Фридриха Вильгельма IV императору Николаю I, установленный здесь в 1845–1846 годах по проекту Карла Росси. Скульптуры созданы немецким мастером К.Д. Раухом для Берлина, а их петербургские копии водрузили на 12-метровые колонны в память о победах русских войск в Отечественной войне 1812 года.

Главная архитектурная доминанта бульвара — здание Конногвардейского манежа, построенное в 1804–1807 годах по проекту Джакомо Кваренги для зимней и летней выучки лейб-гвардии Конного полка. Архитектор, создавая утилитарное сооружение, придал ему величественный облик античного храма. Перед портиком установлены скульптурные группы Диоскуров — Кастора и Поллукса, укрощающих коней. Это копии античных статуй у Квиринальского дворца в Риме, выполненные скульптором Паоло Трискорни в 1810 году и доставленные в Петербург лишь в 1816-м.

В 1930-е годы здание приспособили под гараж НКВД, а в годы войны оно серьезно пострадало от обстрелов. В 1977 году, после масштабной реконструкции, манеж открылся как Центральный выставочный зал и по сей день остается одной из главных выставочных площадок города, где проходят крупнейшие художественные проекты.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 7.2 Дворец бракосочетания №1 (особняк А.П. Кельха)
SET @ord = 2;
UPDATE a SET a.[описание] = N'С Английской набережной перед вами предстанет здание, которое трудно не заметить: роскошный особняк с богатым скульптурным декором. Это Дворец бракосочетания №1, а в прошлом — особняк Александра Фердинандовича Кельха.

История этого дома — история любви и аристократического блеска. Изначально здесь стоял типовой дом майора Полянского, затем им владел Никита Всеволожский, богатейший человек и близкий друг Пушкина. Пропив состояние, он продал дом на аукционе, и его приобрел Павел фон Дервиз — миллионер, строитель железных дорог. Его вдова, Вера Николаевна, подарила дом сыну и перестроила его в роскошный дворец во флорентийском стиле. В 1903 году особняк купил великий князь Андрей Владимирович, внук Александра II.

Но подлинная слава пришла к дому благодаря связи князя с Матильдой Кшесинской — знаменитой балериной, незадолго до этого расставшейся с будущим императором Николаем II. Кшесинская была старше Андрея Владимировича на шесть лет, но это не помешало их роману. В 1902 году у них родился сын Владимир, а официально отношения узаконили лишь в 1921 году в эмиграции.

В советское время, 1 января 1960 года, в этом особняке открылся первый в Ленинграде Дворец бракосочетания. Именно здесь зародилась традиция дворцовых церемоний, распространившаяся потом по всей стране. За более чем полвека здесь создали свои семьи почти полмиллиона пар.'
