-- Route 8: Путешествие по набережной Мойки (Восточное)
--------------------------------------------------------------------------------
SELECT @routeId = [id_маршрута] FROM [маршрут] WHERE [название] = N'Путешествие по набережной Мойки';
IF @routeId IS NULL
BEGIN
  RAISERROR(N'Маршрут 8 не найден в таблице [маршрут].', 16, 1);
  RETURN;
END

-- 8.1 ДК Связи
SET @ord = 1;
UPDATE a SET a.[описание] = N'Наш маршрут начинается от одного из самых ярких памятников советской архитектуры в центре Петербурга — Дворца культуры связи имени С. М. Кирова. Это здание на пересечении Большой Морской улицы и Почтамтского переулка — впечатляющий образец конструктивизма, стиля, которым молодое советское государство заявляло о себе.

Здание было построено в 1930–1933 годах по проекту архитектора Петра Михайловича Гринберга при участии Георгия Сергеевича Райца. Изначально оно предназначалось для работников почтово-телеграфной отрасли и носило название «Дворец культуры связи». Массивные геометрические объёмы, ленточное остекление, асимметричная композиция — всё это характерные черты конструктивизма, стремившегося к функциональности и выразительности без излишнего декора.

Дворец стал настоящим культурным центром для тысяч ленинградцев. В его стенах работали библиотека, театральная студия, спортивные секции, проводились лекции и кинопоказы. В годы войны здание не прекращало работу, а после блокады стало одним из центров возрождения культурной жизни города.

Сегодня ДК Связи сохраняет своё просветительское назначение. Здесь проходят концерты, спектакли, выставки, работают творческие коллективы. Здание остаётся не только памятником архитектуры, но и живым культурным пространством, связывающим эпохи.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.2 Дом Билдерлингов
SET @ord = 2;
UPDATE a SET a.[описание] = N'На пересечении Большой Морской улицы и Почтамтского переулка стоит здание, которое не спешит раскрывать своё прошлое. Снаружи — строгий фасад. Внутри — другое, почти сказочное измерение. Это особняк, связанный с именами многих известных владельцев, но в историю вошедший как дом Бильдерлингов.

История участка уходит в петровскую эпоху: в начале XVIII века здесь находилась Морская слобода, застроенная домами служителей Адмиралтейства. После пожаров 1736–1737 годов территорию перепланировали, и в 1741 году участок получил советник Адмиралтейств-коллегии Я. Л. Хитрово, построивший здесь особняк.

В конце 1880-х годов дом приобрёл генерал-майор Пётр Алексеевич Бильдерлинг — артиллерист, промышленник, человек эпохи больших перемен. При нём здание обрело свой нынешний облик, а интерьеры получили уникальное оформление, которое изумляет до сих пор.

Парадный вестибюль встречает кирпичной кладкой с надписью «Бильдерлингъ» и мраморной лестницей, которую охраняют две кариатиды. Узоры на ступенях напоминают морские канаты — словно дом помнил своё «морское» происхождение.

Анфилада комнат третьего этажа делила пространство на мужскую и женскую половины. В Охотничьем кабинете — ореховые панели, резные панно с орлами и собаками, оружие. Мавританская ванная комната отделана метлахской плиткой и фризом с цитатами из Корана — дань восточной моде конца XIX века.

Главное сокровище дома — столовая. Над окнами — гипсовые совы и медведи, на стенах — слоны с арапами из папье-маше. Потолок держат рыцарские шлемы, а кессоны расписаны знаками зодиака — по числу детей Бильдерлинга, которых у него было одиннадцать.

В гостиной-эркере сохранился уникальный фонтан «Рождение Афродиты» с дельфинами и амурами, действовавший ещё в XIX веке. Голубой мрамор, латунные детали камина, лёгкий шум воды создают почти театральную атмосферу. Сегодня в особняке открыта гостиница, а уникальные интерьеры доступны для осмотра в рамках экскурсий.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.3 Особняк Гагарина (Дом Половцева)
SET @ord = 3;
UPDATE a SET a.[описание] = N'Продолжая прогулку по Большой Морской улице, обратите внимание на здание под номером 52. Снаружи — классический особняк с полукруглым эркером. Но за этим строгим фасадом скрывается один из самых роскошных интерьерных ансамблей Петербурга, который создавался лучшими архитекторами второй половины XIX века.

История участка начинается в 1710-х годах, когда здесь находилась усадьба графа Гавриила Ивановича Головкина, первого канцлера Российской империи. В 1835–1836 годах дом полностью перестроил архитектор Александр Христофорович Пель для князя Павла Ивановича Гагарина.

Новый этап в жизни особняка начался в 1864 году, когда его приобрёл Александр Александрович Половцов — сенатор, государственный секретарь, председатель Русского исторического общества. Половцов был женат на Надежде Михайловне Июневой, приёмной дочери барона Александра Людвиговича Штиглица — крупнейшего финансиста и мецената. Получив за женой огромное приданое, Половцов решил превратить свой дом в настоящий дворец.

На протяжении двух десятилетий над интерьерами работала целая плеяда выдающихся архитекторов: Гаральд Боссе, Николай Брюллов, Людвиг Петерсон, Людвиг Маршнер, Максимилиан Месмахер. Каждый из них создавал интерьеры в разных исторических стилях, превратив особняк в своеобразную энциклопедию европейского искусства.

Сохранилась парадная лестница, украшенная гобеленами с уникальной историей: они были подарены императору Александру I Наполеоном, а после падения французского императора государь подарил их одному из своих приближённых, откуда они и попали к Половцову.

Белый зал выполнен в стиле Людовика XV. Будуар с эркером на Морскую улицу когда-то был наполнен живыми цветами, создавая атмосферу зимнего сада. Красная гостиная разделена аркой на две части. Большая библиотека в флорентийском стиле — шедевр, который устанавливал на место профессор Н. Ф. Брюллов. Максимилиан Месмахер создал Банкетный зал, Портретную комнату, столовую с отделкой из ореха и кордуанской кожи. Людвиг Маршнер оформил так называемую «библиотеку Oppenor''а», серую гостиную с гобеленами и курительную.

С 1934 года в особняке размещается Дом архитектора. Здесь проходят заседания, концерты, выставки. В 1980-х годах проведена масштабная реставрация. Вход в Дом архитектора открыт для посещения мероприятий.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.4 Памятник Николаю I
SET @ord = 4;
UPDATE a SET a.[описание] = N'В центре Исаакиевской площади, между Мариинским дворцом и собором, возвышается конная статуя императора Николая I. Памятник был открыт 25 июня 1859 года по указу его сына — императора Александра II. Автором проекта выступил архитектор Огюст Монферран — создатель Исаакиевского собора и Александровской колонны.

Шестиметровая конная статуя выполнена скульптором Петром Карловичем Клодтом. Император изображён в парадном мундире лейб-гвардии Конного полка. Для скульптуры позировал любимый жеребец государя по кличке Амалатбек.

Для своего времени памятник считался техническим чудом: это была первая в Европе конная статуя, поставленная всего на две точки опоры. Впервые такой приём использовали при создании памятника президенту Эндрю Джексону в Вашингтоне, и Клодт сумел повторить этот сложнейший инженерный трюк.

Пьедестал выполнен из малинового карельского шокшинского кварцита и белого итальянского мрамора. Четыре аллегорические женские фигуры работы Роберта Залемана олицетворяют Силу, Мудрость, Правосудие и Веру. Их лица имеют портретное сходство с императрицей Александрой Фёдоровной и дочерьми Николая I — Марией, Александрой и Ольгой.

На постаменте размещены четыре барельефа (работы Николая Рамазанова и Роберта Залемана), изображающие ключевые события правления Николая I: восстание декабристов на Сенатской площади, усмирение холерного бунта на Сенной, вручение награды М. М. Сперанскому за составление первого Свода законов и открытие Веребьинского моста на железной дороге Петербург — Москва.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.5 Исаакиевский собор и сквер
SET @ord = 5;
UPDATE a SET a.[описание] = N'Исаакиевский собор — крупнейший православный храм Санкт-Петербурга, одна из главных архитектурных доминант города. Его золотой купол виден из многих точек центра, а высота здания достигает 101,5 метра.

История собора начинается с первой деревянной Исаакиевской церкви, заложенной в 1710 году на Адмиралтейском лугу. Именно здесь 19 февраля 1712 года венчались Пётр I и Екатерина Алексеевна. Вторая, каменная церковь в стиле петровского барокко, строилась в 1717–1727 годах по проекту Георга Маттарнови и напоминала Петропавловский собор. Третий собор, заложенный в 1768 году по проекту Антонио Ринальди, так и не был завершён. Современное здание — четвёртое по счёту. Оно строилось рекордно долго: с 1818 по 1858 год, целых 40 лет. Автор проекта — архитектор Огюст Монферран, для которого этот храм стал главным делом жизни.

Николай I лично курировал строительство. При возведении использовались передовые технологии: для подъёма колонн создали специальные деревянные леса, а купол выполнили из металлических конструкций — новаторство для того времени. Наружные колонны — монолитные гранитные блоки весом от 64 до 114 тонн.

В отделке интерьеров использовано около 20 видов цветного камня: малахит, лазурит, порфир, разноцветные мраморы. Плафон главного купола расписан Карлом Брюлловым. Витражи, мозаика, скульптура — всё это делает собор настоящим музеем декоративно-прикладного искусства.

Торжественное освящение состоялось 30 мая 1858 года. С 1858 по 1929 год собор был кафедральным, а с 1928 года имеет статус музея. В 1991 году зарегистрирована церковная община, и с тех пор богослужения проводятся ежедневно.

Перед южным фасадом собора разбит Исаакиевский сквер. Он был устроен в 1860 году по повелению Александра II на месте строительных лесов и временных построек. 30 июня 1860 года император повелел назвать сквер Исаакиевским, а 19 июля того же года он был открыт для публики. Сегодня это любимое место отдыха горожан и гостей города, откуда открываются великолепные виды на собор, памятник Николаю I и Мариинский дворец.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.6 Мариинский дворец
SET @ord = 6;
UPDATE a SET a.[описание] = N'На противоположной стороне Исаакиевской площади высится величественное здание Мариинского дворца — один из трёх «политических» дворцов Петербурга наряду с Зимним и Таврическим. Сегодня здесь заседает Законодательное собрание города. В 1768 году по проекту Жана-Батиста Валлен-Деламота здесь возвели роскошный дворец. После смерти Чернышёва имение отошло в казну, а в 1824 году его передали военному ведомству. Здесь разместилась школа Гвардейских подпрапорщиков, где в 1832–1834 годах учился Михаил Лермонтов.

В 1838 году Николай I решил построить здесь дворец для своей дочери Марии Николаевны в честь её помолвки с герцогом Максимилианом Лейхтенбергским. Проект поручили Андрею Ивановичу Штакеншнейдеру, который впоследствии стал лучшим зодчим великокняжеских дворцов. Строительство велось в 1839–1844 годах.

Архитектор гениально вписал дворец в сложный участок неправильной формы, сохранив роль архитектурной доминанты за Исаакиевским собором. При строительстве применялись новейшие технологии: аммосовские печи для обогрева, водопровод, канализация, вентиляция. 28 июля 1839 года состоялась торжественная закладка, а 25 января 1845-го дворец освятили и на время открыли для всех желающих.

При Марии Николаевне во дворце устраивали балы, маскарады, благотворительные вечера. В Ротонде проходили рождественские ёлки для детей, в Квадратном зале ставили любительские спектакли.

В 1880-х дворец выкупили в казну, и он стал резиденцией Государственного совета. В 1906 году Леонтий Бенуа пристроил корпус для Большого зала заседаний. После Февральской революции здесь заседало Временное правительство, после Октябрьской — Высший совет народного хозяйства. С 1945 года во дворце работал Ленсовет, а с 1994-го — Законодательное собрание Санкт-Петербурга.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.7 Дом у Красного моста (Особняк Косиковского)
SET @ord = 7;
UPDATE a SET a.[описание] = N'Прогуливаясь по набережной реки Мойки, вы обязательно заметите нарядный угловой дом у Красного моста. Это один из знаменитых «цветных» мостов Петербурга, а сам особняк — классический пример столичного доходного дома XIX века.

Красный мост — единственный из четырёх «цветных» мостов через Мойку (наряду с Синим, Жёлтым и Зелёным), сохранивший своё историческое название. Он был перестроен в камне в 1808–1814 годах по типовому проекту Вильяма Гесте и инженера Е. А. Адама.

Особняк на набережной Мойки, 73 (угол с улицей Гороховой), известен как дом купца Косиковского. Здание было построено в 1830-х годах и неоднократно перестраивалось. Его фасады решены в стиле позднего классицизма с элементами эклектики.

После революции 1917 года дом был национализирован. Как и многие доходные дома в центре Петрограда, он был переоборудован под коммунальные квартиры. В его стенах поселились десятки семей, а роскошные интерьеры бывших купеческих апартаментов были перепланированы под жильё.

Сегодня дом у Красного моста — это жилой и административный комплекс, имеющий статус объекта культурного наследия регионального значения. Здание находится под охраной государства как ценный элемент исторической застройки центра Петербурга.

На первых этажах здания, выходящих на набережную Мойки и Гороховую улицу, традиционно располагаются коммерческие помещения: магазины, офисы, кафе. Это продолжает историческую традицию доходного дома, где первые этажи всегда сдавались под лавки и торговые заведения.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.8 Строгановский дворец
SET @ord = 8;
UPDATE a SET a.[описание] = N'На углу Невского проспекта и набережной Мойки стоит Строгановский дворец — шедевр русского барокко, созданный великим Франческо Бартоломео Растрелли. Это родовой дворец знаменитой семьи промышленников и меценатов Строгановых, ныне филиал Русского музея.

Здание было построено в 1753–1754 годах для барона Сергея Григорьевича Строганова. Первоначально вход осуществлялся со двора в корпус, стоящий на набережной Мойки.

В конце XVIII — начале XIX века Андрей Воронихин, крепостной Строгановых, ставший знаменитым архитектором, перестроил северо-западный угол здания, устроив вход с Невского проспекта, и создал ряд интерьеров в стиле классицизма. В 1842 году Пётр Садовников завершил формирование южного корпуса и стилистически объединил все дворовые фасады в духе Растрелли.

Главная гордость дворца — Большой зал (Банкетный), единственный интерьер, сохранивший подлинное декоративное убранство Растрелли и уникальный плафон Джованни Батисты Валериани «Триумф Героя».

В 1918 году дворец национализировали и открыли в нём «Народный дом-музей». Однако в 1929 году помещения передали ВАСХНИЛ, а коллекции распределили по разным музеям или продали за границу. До 1988 года здесь размещались различные учреждения, главным из которых был «Электромортрест», затем Ленинградское предприятие «Эра». В 1988 году здание передали Русскому музею, реставрация 1989–2003 годов вернула ему первоначальный облик. В 1992 году в Нью-Йорке учредили Благотворительный Строгановский фонд для поддержки реставрации.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.9 Дворец графа Разумовского
SET @ord = 9;
UPDATE a SET a.[описание] = N'На набережной Мойки, 48, расположен обширный дворец в стиле классицизма, построенный для последнего гетмана Войска Запорожского — графа Кирилла Григорьевича Разумовского.

Дворец был возведён в 1762–1766 годах по проекту архитектора Александра Филипповича Кокоринова при участии Жана-Батиста Валлен-Деламота. Это один из немногих сохранившихся в Петербурге частных дворцов середины XVIII века.

Центральный корпус украшен коринфским портиком с фронтоном, боковые крылья завершаются павильонами. Парадный двор (курдонёр) отделён от набережной изящной чугунной оградой. В отделке интерьеров участвовали лучшие мастера своего времени.

При Разумовском во дворце проходили пышные балы и приёмы, гремела музыка, собирался весь цвет екатерининской эпохи. После смерти графа дворец неоднократно перестраивался и менял владельцев. В XIX веке здесь размещались различные учебные заведения и учреждения. В настоящее время дворец является объектом культурного наследия федерального значения, включённым в Единый государственный реестр объектов культурного наследия народов Российской Федерации.

Здание занимает Российский государственный педагогический университет имени А. И. Герцена (РГПУ им. А. И. Герцена). Здесь размещаются университетские аудитории, библиотека и музей РГПУ.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

-- 8.10 Казанский собор
SET @ord = 10;
UPDATE a SET a.[описание] = N'Казанский собор — главная архитектурная доминанта Невского проспекта и один из крупнейших храмов города. Он был построен в 1801–1811 годах по проекту архитектора Андрея Никифоровича Воронихина для перенесения чтимого списка Казанской иконы Божией Матери.

Император Павел I пожелал, чтобы новый собор напоминал собор Святого Петра в Риме. Отсюда грандиозная полукруглая колоннада из 96 колонн коринфского ордера, раскрытая к Невскому проспекту. Воронихин блестяще решил сложнейшую градостроительную задачу, создав площадь, органично вписавшуюся в магистраль.

Собор стал памятником русской воинской славы. В 1813 году здесь был погребён фельдмаршал Михаил Илларионович Кутузов, а в 1837 году перед собором установили памятники Кутузову и Барклаю-де-Толли работы скульптора Бориса Орловского. В соборе хранятся трофейные знамёна и ключи от городов, взятых русской армией.

Интерьер собора поражает величественным пространством. 56 монолитных колонн из розового финского гранита образуют нефы. Главная святыня — Казанская икона Божией Матери, одна из самых почитаемых в России.

После революции 1917 года собор продолжал действовать до 1929 года. В 1922 году из него изъяли церковные ценности под предлогом помощи голодающим. В 1929 году собор закрыли, а в 1932 году в нём открылся Музей истории религии и атеизма. Здание перестраивалось под музейные нужды: были заложены некоторые окна, уничтожены настенные росписи, на куполе установили флагшток.

В 1991 году в соборе возобновились богослужения. Сегодня Казанский собор — действующий кафедральный собор Санкт-Петербургской епархии Русской Православной Церкви. Он открыт ежедневно для посещения и богослужений. Здесь хранится множество святынь: мощи святых, чтимые иконы.'
FROM [достопримечательность] a JOIN [точка_маршрута] p ON p.[id_достопримечательности]=a.[id_достопримечательности]
WHERE p.[id_маршрута]=@routeId AND p.[порядок_следования]=@ord;

PRINT N'Готово: описания заполнены для маршрутов 5-8.';

